        margin = (opd[rx][ry] - myd[rx][ry])  # positive means we are closer
        if margin > best_margin or (margin == best_margin and d1 < myd[best_target[0]][best_target[1]] if best_target else True):
            best_margin = margin
            best_target = (rx, ry)

    tx, ty = best_target
    best_move = (0, 0)
    best_val = -10**18

    for dx, dy in deltas:
        nx, ny = sx + dx, sy + dy
        if not inside(nx, ny):
            continue
        v = -myd[nx][ny] + 0.3 * opd[nx][ny]  # discourage moves that bring us closer to opponent's perspective
        # stronger push: prefer decreasing distance to target and increasing the margin there
        v += 2.0 * (myd[sx][sy] - myd[nx][ny])
        v += 1.5 * (opd[tx][ty] - myd[nx][ny])
        if v > best_val or (v == best_val and (dx, dy) < best_move):
            best_val = v
            best_move = (dx, dy)

    return [int(best_move[0]), int(best_move[1])]

